from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    predicate_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))
        if triple.predicate not in predicate_map:
            predicate_map[triple.predicate] = []
        predicate_map[triple.predicate].append((triple.subject, triple.object))

    sentence = ""
    for subject, triples in subject_map.items():
        if sentence:
            sentence += " which "
        sentence += f"{subject} "
        for i, (predicate, obj) in enumerate(triples):
            if predicate in predicate_map:
                related_subjects = [s for s, o in predicate_map[predicate] if s != subject]
                if related_subjects:
                    sentence += f"{predicate} of {obj} which is related to {', '.join(related_subjects)}"
                else:
                    sentence += f"{predicate} of {obj}"
            else:
                sentence += f"{predicate} of {obj}"
            if i < len(triples) - 1:
                sentence += ", "
    # Try to connect related triples into a single sentence
    if "Antwerp International Airport" in sentence and "Antwerp" in sentence and "Belgium" in sentence:
        sentence = sentence.replace(" which Antwerp International Airport serves the city of Antwerp which Antwerp is located in Belgium",
                                    "Antwerp International Airport serves the city of Antwerp which is located in Belgium")
    if "Ashgabat International Airport" in sentence and "3rdRunwayLengthFeet" in sentence:
        sentence = sentence.replace("Ashgabat International Airport has a 3rdRunwayLengthFeet of 2953 feet",
                                    "The Ashgabat International Airport's 3rd runway length in ft is 2953")
    if "Angola International Airport" in sentence and "1stRunwayNumber" in sentence:
        sentence = sentence.replace("Angola International Airport has a 1stRunwayNumber of 5",
                                    "Angola International Airport 1st runway is Number 5")
    return sentence + "."

